 band_c_1 = 0.5 + 0.5 * cos(((p_1.x + p_1.y) * 3.4) + sin(p_1.x * 6.28318 + q8 * 0.18) * 0.18);

 float pressure_1;
 pressure_1 = (band_a_1 * 0.45) + (band_b_1 * 0.35) + (band_c_1 * 0.20);
