warp_hlsl:
shader_body
{
    float energy = saturate(q4);
    float2 p = uv_orig*2-1;
    float2 flow;
    flow.x = sin(p.y*6 + q8*0.37);
    flow.y = cos((p.x+p.y)*4.5 - q8*0.29);
    flow *= texsize.zw*(1.2+energy*6);
    float3 prev = tex2D(sampler_main, uv+flow).xyz;
    float3 blur = GetBlur1(uv);
    ret = lerp(prev, blur, 0.035+0.045*energy);
    ret -= 0.0038+0.002*energy;
}

comp_hlsl:
shader_body
{
    float energy = saturate(q4);
    float2 p = uv_orig;

    float3 feedback = tex2D(sampler_main, uv).xyz;
    float3 blur1 = GetBlur1(uv);
    float3 blur2 = GetBlur2(uv);
    float3 blur3 = GetBlur3(uv);

    float3 base = feedback*0.64 + blur1*0.22 + blur2*0.10 + blur3*0.08;

    float drift = q8*0.010;

    float bandA = 0.5 + 0.5*sin(p.y*7.0 + p.x*0.6 + drift);
    float bandB = 0.5 + 0.5*sin(p.x*4.3 - p.y*2.2 - drift*0.72);
    float bandC = 0.5 + 0.5*cos((p.x+p.y)*3.4 + sin(p.x*6.28318 + q8*0.18)*0.18);

    float pressure = bandA*0.45 + bandB*0.35 + bandC*0.20;
    pressure = smoothstep(0.12,0.88,pressure);

    float2 softOffset;
    softOffset.x = (bandB-0.5)*texsize.z;
    softOffset.y = (bandC-0.5)*texsize.w;
    softOffset *= 1.5 + energy*5.0;

    float3 driftSample = tex2D(sampler_main, uv + softOffset).xyz;
    base = lerp(base, driftSample, 0.12 + energy*0.08);

    float3 c1 = float3(q1,q2,q3);
    float3 c2 = float3(q2,q3,q1);
    float3 c3 = float3(q3,q1,q2);

    float3 tint = lerp(c1, c2, bandB);
    tint = lerp(tint, c3, bandC*0.35);

    float3 field = base;
    field = lerp(field, field*(0.78 + tint*0.46), 0.20 + energy*0.10);
    field += tint * pressure * (0.045 + energy*0.055);

    float gray = dot(field, float3(0.3333,0.3333,0.3333));
    field = lerp(gray, field, 1.06 + energy*0.22);

    float2 center = p - float2(0.5,0.5);
    float vignette = 1.0 - dot(center,center)*0.30;
    field *= (0.86 + energy*0.12) * vignette;

    float maxChannel = max(max(field.r, field.g), field.b);
    float limiter = 1.0 / (1.0 + max(0.0, maxChannel - 0.78)*1.85);
    field *= limiter;

    ret = clamp(field, 0.0, 0.94);
}
